   124→        // Rank categories by score and apply selection logic
   125→        const rankedCategories = this._rankCategoriesByScore(candidateScores);
   126→        const selectedLabels = this._selectLabels(
   127→          rankedCategories,
   128→          maxLabels,
   129→          minSecondaryConfidence,
