   196→   */
   197→  _rankCategoriesByScore(candidateScores) {
   198→    return Object.entries(candidateScores)
   199→      .map(([categoryCode, scoreData]) => ({
   200→        category: categoryCode,
   201→        score: scoreData.score || 0,
   202→        confidence: scoreData.confidence || 0,
   203→        scoring_components: scoreData.scoring_components || {},
   204→        rationale: scoreData.rationale || '',
