/**
 * EmailCategorizer Node: Multi-Label Selection
 *
 * PURPOSE
 *  Stage 7 of the EmailCategorizer pipeline. Ranks categories by final scores and selects
 *  up to 3 labels based on confidence thresholds and co-presence policies. Implements
 *  sophisticated multi-label selection logic with primary/secondary label relationships.
 *
 * PROCESSING LOGIC
 *  1. Load configuration and input email data with disambiguated candidate scores
 *  2. Rank all categories by final score (highest to lowest)
 *  3. Select primary label (highest scoring category above confidence threshold)
 *  4. Select secondary labels based on gap rules and allowed combinations
 *  5. Apply multi-label policy constraints (max 3 labels, minimum confidence)
 *  6. Create final label selection with confidence and subtype assignments
 *  7. Pass selected labels to AI routing stage
 *
 * DATABASE OPERATIONS
 *  - None (pure business logic node)
 *  - Database persistence handled by separate prepare_multi_label_persistence node
 *
 * EXPECTED INPUT (from DisambiguationNode)
 *  Array of email objects with:
 *  - gmail_id, session_id, candidate_scores (with disambiguation applied)
 *  - detected_attributes: [{attribute_name, attribute_value, influence_role, ...}]
 *  - stage_id from disambiguation stage
 *
 * OUTPUT FORMAT
 *  Email objects with selected labels for AI routing:
 *  [{
 *    gmail_id: string,
 *    session_id: string,
 *    selected_labels: [{
 *      category: string,
 *      subtype: string (optional),
 *      confidence: number,
 *      score: number,
 *      is_primary: boolean,
 *      label_order: number,
 *      selection_rationale: string
 *    }],
 *    candidate_scores: {...}, // preserved for AI routing
 *    needs_ai_classification: boolean,
 *    selection_summary: {
 *      total_labels: number,
 *      primary_category: string,
 *      confidence_range: [min, max],
 *      selection_method: string
 *    },
 *    // ... original email fields
 *  }]
 *
 * CONFIGURATION DEPENDENCIES
 *  - config.processing_config.settings.multi_label_selection (max_labels, min_secondary_confidence, allowed_combinations)
 *  - config.confidence_thresholds (high_confidence, medium_confidence, low_confidence, secondary_label_min_gap)
 *  - config.multi_label_policy (max_top_level_labels, min_confidence_for_additional, allowed combinations)
 *
 * MULTI-LABEL SELECTION LOGIC
 *  - Primary Label: Highest scoring category above minimum threshold (default: 3)
 *  - Secondary Labels: Within configured gap of primary (default: 2 points) and above minimum confidence
 *  - Allowed Combinations: Explicit whitelist (e.g., financial+actionable)
 *  - Maximum Labels: Hard cap (default: 3) to prevent over-labeling
 *  - Confidence Filters: Minimum confidence thresholds for primary (8) and secondary (6) labels
 *
 * DECISION CLASSIFICATION
 *  - positive: score >= high_confidence (15) - Finalized without AI
 *  - candidate: score >= medium_confidence (8) and < high_confidence - May need AI
 *  - rejected: score < low_confidence (3) - Not selected
 *
 * Extends CodeNode from n8n-simulator for local testing and development.
 */

const CodeNode = require('../../../../n8n-simulator/src/nodes/CodeNode');

class MultiLabelSelectionNode extends CodeNode {
  constructor() {
    super('MultiLabelSelection');
  }

  async execute($input) {
    const inputItems = $input.all();
    console.log('Starting multi_label_selection node execution');

    // Load cached configuration
    const staticData = $getWorkflowStaticData('global');
    const config = staticData.email_categorizer_config?.config;
    if (!config) {
      throw new Error('Email categorizer configuration not found in static data');
    }

    const multiLabelSettings = config.processing_config?.settings?.multi_label_selection || {};
    const confidenceThresholds = config.confidence_thresholds || {};
    const multiLabelPolicy = config.multi_label_policy || {};

    // Extract configuration values with defaults
    const maxLabels = multiLabelSettings.max_labels || multiLabelPolicy.max_top_level_labels || 3;
    const minSecondaryConfidence =
      multiLabelSettings.min_secondary_confidence || multiLabelPolicy.min_confidence_for_additional || 6;
    const allowedCombinations = multiLabelSettings.allowed_combinations || [];

    const highConfidenceThreshold = confidenceThresholds.high_confidence || 15;
    const mediumConfidenceThreshold = confidenceThresholds.medium_confidence || 8;
    const lowConfidenceThreshold = confidenceThresholds.low_confidence || 3;
    const secondaryLabelMinGap = confidenceThresholds.secondary_label_min_gap || 2;

    console.log(`Multi-label selection processing ${inputItems.length} emails with max ${maxLabels} labels`);
    console.log(
      `Confidence thresholds - High: ${highConfidenceThreshold}, Medium: ${mediumConfidenceThreshold}, Low: ${lowConfidenceThreshold}`
    );

    const results = [];

    for (const item of inputItems) {
      const emailData = item.json;
      console.log(`Processing multi-label selection for email ${emailData.gmail_id}`);

      try {
        // Get disambiguated candidate scores
        const candidateScores = emailData.candidate_scores || {};
        console.log(
          `Processing ${Object.keys(candidateScores).length} candidate categories for email ${emailData.gmail_id}`
        );

        // Rank categories by score and apply selection logic
        const rankedCategories = this._rankCategoriesByScore(candidateScores);
        const selectedLabels = this._selectLabels(
          rankedCategories,
          maxLabels,
          minSecondaryConfidence,
          highConfidenceThreshold,
          mediumConfidenceThreshold,
          lowConfidenceThreshold,
          secondaryLabelMinGap,
          allowedCombinations
        );

        // Update candidate scores with final decisions (in memory only)
        this._updateCategoryDecisions(
          candidateScores,
          selectedLabels,
          highConfidenceThreshold,
          mediumConfidenceThreshold,
          lowConfidenceThreshold
        );

        // Determine if AI classification is needed
        const needsAiClassification = this._determineAiClassificationNeed(
          selectedLabels,
          highConfidenceThreshold,
          mediumConfidenceThreshold
        );

        // Create selection summary
        const selectionSummary = this._createSelectionSummary(selectedLabels, rankedCategories, needsAiClassification);

        // Return email data with selected labels (no database operations)
        const labeledEmailData = {
          ...emailData,
          selected_labels: selectedLabels,
          candidate_scores: candidateScores, // Preserve for AI routing
          needs_ai_classification: needsAiClassification,
          selection_summary: selectionSummary,
          // Add data for database persistence preparation
          _persistence_data: {
            stage_type: 'multi_label_selection',
            stage_order: 7,
            selected_labels: selectedLabels,
            selection_summary: selectionSummary,
            session_categories: this._prepareSessionCategories(selectedLabels, emailData.session_id),
            category_decisions: this._prepareCategoryDecisions(candidateScores, selectedLabels),
          },
        };

        results.push({ json: labeledEmailData });
        console.log(
          `Multi-label selection completed for email ${emailData.gmail_id}: ${selectedLabels.length} labels selected (AI needed: ${needsAiClassification})`
        );
      } catch (error) {
        console.error(`Error processing multi-label selection for email ${emailData.gmail_id}:`, error);
        // Continue with other emails but preserve original data
        results.push({
          json: {
            ...emailData,
            multi_label_selection_error: error.message,
          },
        });
      }
    }

    console.log(`Multi-label selection processing completed for ${results.length} emails`);
    return results;
  }

  /**
   * Rank categories by final score (highest to lowest)
   */
  _rankCategoriesByScore(candidateScores) {
    return Object.entries(candidateScores)
      .map(([categoryCode, scoreData]) => ({
        category: categoryCode,
        score: scoreData.score || 0,
        confidence: scoreData.confidence || 0,
        scoring_components: scoreData.scoring_components || {},
        rationale: scoreData.rationale || '',
        selected_subtype_id: scoreData.selected_subtype_id || null,
      }))
      .filter((cat) => cat.score > 0) // Only consider categories with positive scores
      .sort((a, b) => b.score - a.score); // Sort by score descending
  }

  /**
   * Select labels based on multi-label selection logic
   */
  _selectLabels(
    rankedCategories,
    maxLabels,
    minSecondaryConfidence,
    highConfidenceThreshold,
    mediumConfidenceThreshold,
    lowConfidenceThreshold,
    secondaryLabelMinGap,
    allowedCombinations
  ) {
    const selectedLabels = [];

    if (rankedCategories.length === 0) {
      console.log('No categories with positive scores to select from');
      return selectedLabels;
    }

    console.log('Ranked categories:', rankedCategories.map((cat) => `${cat.category}: ${cat.score}`).join(', '));

    // Select primary label (highest scoring category above minimum threshold)
    const primaryCandidate = rankedCategories[0];
    if (primaryCandidate.score >= lowConfidenceThreshold) {
      const primaryLabel = {
        category: primaryCandidate.category,
        subtype: primaryCandidate.selected_subtype_id,
        confidence: primaryCandidate.confidence,
        score: primaryCandidate.score,
        is_primary: true,
        label_order: 1,
        selection_rationale: `Primary label: highest score (${primaryCandidate.score}) above minimum threshold (${lowConfidenceThreshold})`,
      };

      selectedLabels.push(primaryLabel);
      console.log(
        `Selected primary label: ${primaryCandidate.category} (score: ${primaryCandidate.score}, confidence: ${primaryCandidate.confidence}%)`
      );
    } else {
      console.log(
        `No primary label selected - highest score ${primaryCandidate.score} below minimum threshold ${lowConfidenceThreshold}`
      );
      return selectedLabels;
    }

    // Select secondary labels if within gap threshold and above minimum confidence
    if (maxLabels > 1 && rankedCategories.length > 1) {
      const primaryScore = primaryCandidate.score;

      for (let i = 1; i < rankedCategories.length && selectedLabels.length < maxLabels; i++) {
        const candidate = rankedCategories[i];
        const scoreDifference = primaryScore - candidate.score;

        // Check if candidate meets secondary label criteria
        if (candidate.score >= minSecondaryConfidence && scoreDifference <= secondaryLabelMinGap) {
          // Check if combination is allowed
          const primaryCategory = primaryCandidate.category;
          const candidateCategory = candidate.category;

          if (this._isCombinationAllowed(primaryCategory, candidateCategory, allowedCombinations)) {
            const secondaryLabel = {
              category: candidate.category,
              subtype: candidate.selected_subtype_id,
              confidence: candidate.confidence,
              score: candidate.score,
              is_primary: false,
              label_order: selectedLabels.length + 1,
              selection_rationale: `Secondary label: score (${candidate.score}) within gap (${scoreDifference} <= ${secondaryLabelMinGap}) and above minimum confidence (${minSecondaryConfidence})`,
            };

            selectedLabels.push(secondaryLabel);
            console.log(
              `Selected secondary label: ${candidate.category} (score: ${candidate.score}, gap: ${scoreDifference})`
            );
          } else {
            console.log(`Combination ${primaryCategory}+${candidateCategory} not allowed - skipping secondary label`);
          }
        } else {
          const reason =
            candidate.score < minSecondaryConfidence
              ? `below minimum confidence (${candidate.score} < ${minSecondaryConfidence})`
              : `gap too large (${scoreDifference} > ${secondaryLabelMinGap})`;
          console.log(`Candidate ${candidate.category} rejected as secondary: ${reason}`);
        }
      }
    }

    console.log(`Final label selection: ${selectedLabels.length} labels selected`);
    return selectedLabels;
  }

  /**
   * Check if category combination is allowed
   */
  _isCombinationAllowed(primaryCategory, candidateCategory, allowedCombinations) {
    // Always allow single label
    if (!candidateCategory || primaryCategory === candidateCategory) {
      return true;
    }

    // Check explicit allowed combinations
    const combination1 = `${primaryCategory}+${candidateCategory}`;
    const combination2 = `${candidateCategory}+${primaryCategory}`;

    const isExplicitlyAllowed = allowedCombinations.some((combo) => combo === combination1 || combo === combination2);

    if (isExplicitlyAllowed) {
      console.log(`Combination ${combination1} is explicitly allowed`);
      return true;
    }

    // Default policy: allow if no explicit restrictions (future enhancement: add more sophisticated rules)
    console.log(`Combination ${combination1} not explicitly configured - allowing by default`);
    return true;
  }

  /**
   * Update category decisions in candidate scores (positive/candidate/rejected)
   */
  _updateCategoryDecisions(
    candidateScores,
    selectedLabels,
    highConfidenceThreshold,
    mediumConfidenceThreshold,
    lowConfidenceThreshold
  ) {
    const selectedCategoryNames = new Set(selectedLabels.map((label) => label.category));

    for (const [categoryCode, scoreData] of Object.entries(candidateScores)) {
      const score = scoreData.score || 0;

      if (selectedCategoryNames.has(categoryCode)) {
        // Selected categories get decision based on confidence
        if (score >= highConfidenceThreshold) {
          scoreData.decision = 'positive';
          scoreData.decision_rationale = `High confidence (${score} >= ${highConfidenceThreshold}) - finalized without AI`;
        } else if (score >= mediumConfidenceThreshold) {
          scoreData.decision = 'candidate';
          scoreData.decision_rationale = `Medium confidence (${score} >= ${mediumConfidenceThreshold}) - may need AI validation`;
        } else {
          scoreData.decision = 'candidate';
          scoreData.decision_rationale = `Low confidence (${score} >= ${lowConfidenceThreshold}) - needs AI classification`;
        }
      } else {
        // Non-selected categories are rejected
        scoreData.decision = 'rejected';
        if (score < lowConfidenceThreshold) {
          scoreData.decision_rationale = `Below minimum threshold (${score} < ${lowConfidenceThreshold})`;
        } else {
          scoreData.decision_rationale = `Not selected despite adequate score (${score}) due to multi-label constraints`;
        }
      }

      console.log(
        `Category ${categoryCode}: ${scoreData.decision} (score: ${score}, rationale: ${scoreData.decision_rationale})`
      );
    }
  }

  /**
   * Prepare session_categories data for database persistence
   */
  _prepareSessionCategories(selectedLabels, sessionId) {
    const sessionCategories = [];

    for (const label of selectedLabels) {
      const sessionCategoryData = {
        session_id: sessionId,
        category_code: label.category,
        subtype_code: label.subtype,
        is_primary: label.is_primary,
        confidence: label.confidence,
        category_score: label.score,
        hard_assertion: this._checkHardAssertion(label),
        label_order: label.label_order,
        scoring_trace: {
          selection_rationale: label.selection_rationale,
          final_score: label.score,
          confidence: label.confidence,
        },
      };

      sessionCategories.push(sessionCategoryData);
    }

    return sessionCategories;
  }

  /**
   * Prepare category decisions data for database persistence
   */
  _prepareCategoryDecisions(candidateScores, _selectedLabels) {
    const categoryDecisions = [];

    for (const [categoryCode, scoreData] of Object.entries(candidateScores)) {
      if (scoreData.decision) {
        const categoryDecisionData = {
          category_code: categoryCode,
          decision: scoreData.decision,
          score: scoreData.score || 0,
          confidence: scoreData.confidence || 0,
          decision_rationale: scoreData.decision_rationale || '',
          scoring_components: scoreData.scoring_components || {},
        };

        categoryDecisions.push(categoryDecisionData);
      }
    }

    return categoryDecisions;
  }

  /**
   * Check if label was selected via hard assertion
   */
  _checkHardAssertion(_label) {
    // Check if this label has hard assertion evidence in scoring components
    // This would be set during the initialization/rule scoring stages
    return false; // Placeholder - would check scoring_components.hard_assertion
  }

  /**
   * Determine if AI classification is needed for this email
   */
  _determineAiClassificationNeed(selectedLabels, highConfidenceThreshold, mediumConfidenceThreshold) {
    if (selectedLabels.length === 0) {
      console.log('AI classification needed - no labels selected');
      return true;
    }

    // Check if primary label has high confidence (can skip AI)
    const primaryLabel = selectedLabels.find((label) => label.is_primary);
    if (primaryLabel && primaryLabel.score >= highConfidenceThreshold) {
      console.log(
        `AI classification not needed - primary label ${primaryLabel.category} has high confidence (${primaryLabel.score})`
      );
      return false;
    }

    // Check if any label is below medium confidence (needs AI)
    const hasLowConfidenceLabel = selectedLabels.some((label) => label.score < mediumConfidenceThreshold);
    if (hasLowConfidenceLabel) {
      console.log('AI classification needed - has labels below medium confidence');
      return true;
    }

    console.log('AI classification may be beneficial - medium confidence range');
    return true; // Conservative approach - route uncertain cases to AI
  }

  /**
   * Create selection summary for downstream processing
   */
  _createSelectionSummary(selectedLabels, rankedCategories, needsAiClassification) {
    if (selectedLabels.length === 0) {
      return {
        total_labels: 0,
        primary_category: null,
        confidence_range: [0, 0],
        selection_method: 'none_selected',
        needs_ai: needsAiClassification,
      };
    }

    const confidences = selectedLabels.map((label) => label.confidence);
    const primaryCategory = selectedLabels.find((label) => label.is_primary)?.category || selectedLabels[0].category;

    return {
      total_labels: selectedLabels.length,
      primary_category: primaryCategory,
      confidence_range: [Math.min(...confidences), Math.max(...confidences)],
      selection_method: selectedLabels.length === 1 ? 'single_label' : 'multi_label',
      needs_ai: needsAiClassification,
      top_categories: rankedCategories.slice(0, 3).map((cat) => ({
        category: cat.category,
        score: cat.score,
      })),
    };
  }
}

module.exports = MultiLabelSelectionNode;

