/**
 * Multi-Label Selection Stage - Comprehensive Unit Tests
 *
 * TDD Approach: These tests MUST FAIL before implementation
 *
 * Tests cover:
 * - Ranking algorithms for category scores
 * - Primary/secondary label selection logic
 * - Co-presence rules and allowed combinations
 * - Confidence threshold enforcement
 * - Edge cases and error scenarios
 * - AI routing decision logic
 * - Selection rationale generation
 */

import { MultiLabelSelectionStage } from '../../src/stages/multi-label-selection';
import {
  CategoryScore,
  MultiLabelConfig,
  SelectedLabel,
  SelectionSummary,
  ConfidenceThresholds,
} from '../../src/types';

describe('MultiLabelSelectionStage', () => {
  let stage: MultiLabelSelectionStage;
  let mockConfig: MultiLabelConfig;
  let mockThresholds: ConfidenceThresholds;

  beforeEach(() => {
    // Standard configuration matching email-categorizer-config.json
    mockConfig = {
      maxLabels: 3,
      minSecondaryConfidence: 8,
      allowedCombinations: ['financial+actionable'],
    };

    mockThresholds = {
      highConfidence: 15,
      mediumConfidence: 8,
      lowConfidence: 3,
      secondaryLabelMinGap: 2,
    };

    stage = new MultiLabelSelectionStage(mockConfig, mockThresholds);
  });

  describe('Category Ranking', () => {
    test('should rank categories by score in descending order', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 12, confidence: 85, rationale: 'High financial indicators' },
        actionable: { score: 8, confidence: 70, rationale: 'Action required detected' },
        personal: { score: 5, confidence: 45, rationale: 'Some personal indicators' },
        marketing: { score: 1, confidence: 15, rationale: 'Weak marketing signals' },
      };

      const ranked = stage.rankCategoriesByScore(candidateScores);

      expect(ranked).toHaveLength(4);
      expect(ranked[0]).toMatchObject({
        category: 'financial',
        score: 12,
        confidence: 85,
      });
      expect(ranked[1]).toMatchObject({
        category: 'actionable',
        score: 8,
        confidence: 70,
      });
      expect(ranked[2]).toMatchObject({
        category: 'personal',
        score: 5,
        confidence: 45,
      });
      expect(ranked[3]).toMatchObject({
        category: 'marketing',
        score: 1,
        confidence: 15,
      });
    });

    test('should filter out categories with zero or negative scores', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 12, confidence: 85, rationale: 'Strong signals' },
        actionable: { score: 0, confidence: 0, rationale: 'No signals' },
        personal: { score: -2, confidence: 0, rationale: 'Negative indicators' },
      };

      const ranked = stage.rankCategoriesByScore(candidateScores);

      expect(ranked).toHaveLength(1);
      expect(ranked[0].category).toBe('financial');
    });

    test('should handle empty candidate scores', () => {
      const ranked = stage.rankCategoriesByScore({});
      expect(ranked).toHaveLength(0);
    });
  });

  describe('Primary Label Selection', () => {
    test('should select highest scoring category as primary if above threshold', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 12, confidence: 85, rationale: 'Strong financial signals' },
        actionable: { score: 11, confidence: 70, rationale: 'Action required' }, // Gap of 1, within threshold
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectedLabels).toHaveLength(2); // financial + actionable (allowed combination)
      expect(result.selectedLabels[0]).toMatchObject({
        category: 'financial',
        score: 12,
        isPrimary: true,
        labelOrder: 1,
      });
      expect(result.selectedLabels[0].selectionRationale).toContain('Primary label');
    });

    test('should not select primary if highest score below minimum threshold', () => {
      const candidateScores: Record<string, CategoryScore> = {
        marketing: { score: 2, confidence: 25, rationale: 'Weak signals' },
        personal: { score: 1, confidence: 15, rationale: 'Very weak signals' },
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectedLabels).toHaveLength(0);
      expect(result.selectionSummary.selectionMethod).toBe('none_selected');
    });

    test('should handle single high-confidence category', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 18, confidence: 95, rationale: 'Very strong financial signals' },
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectedLabels).toHaveLength(1);
      expect(result.selectedLabels[0]).toMatchObject({
        category: 'financial',
        isPrimary: true,
        score: 18,
        confidence: 95,
      });
    });
  });

  describe('Secondary Label Selection', () => {
    test('should select secondary labels within score gap and above min confidence', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 12, confidence: 85, rationale: 'Strong financial' },
        actionable: { score: 11, confidence: 80, rationale: 'Strong action required' }, // gap: 1, above min
        personal: { score: 9, confidence: 75, rationale: 'Strong personal' }, // gap: 3, above threshold but gap too large
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectedLabels).toHaveLength(2); // financial + actionable only
      expect(result.selectedLabels[1]).toMatchObject({
        category: 'actionable',
        isPrimary: false,
        labelOrder: 2,
      });
      expect(result.selectedLabels[1].selectionRationale).toContain('Secondary label');
    });

    test('should reject secondary labels with score gap too large', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 12, confidence: 85, rationale: 'Strong financial' },
        actionable: { score: 9, confidence: 75, rationale: 'Action required' }, // gap: 3 > threshold of 2
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectedLabels).toHaveLength(1); // Only primary
      expect(result.selectedLabels[0].category).toBe('financial');
    });

    test('should reject secondary labels below minimum confidence', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 12, confidence: 85, rationale: 'Strong financial' },
        actionable: { score: 11, confidence: 80, rationale: 'Action required' }, // gap: 1, above confidence: should be selected
        personal: { score: 7, confidence: 60, rationale: 'Personal signals' }, // below min confidence of 8
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectedLabels).toHaveLength(2); // financial + actionable only
      expect(result.selectedLabels.map((l) => l.category)).toEqual(['financial', 'actionable']);
    });

    test('should respect maximum label limit', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 15, confidence: 90, rationale: 'Strong financial' },
        actionable: { score: 14, confidence: 88, rationale: 'Strong action' },
        personal: { score: 13, confidence: 85, rationale: 'Strong personal' },
        marketing: { score: 12, confidence: 82, rationale: 'Strong marketing' },
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectedLabels).toHaveLength(3); // Respects maxLabels = 3
      expect(result.selectedLabels.map((l) => l.category)).toEqual(['financial', 'actionable', 'personal']);
    });
  });

  describe('Co-presence Rules and Allowed Combinations', () => {
    test('should allow explicitly configured combinations', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 12, confidence: 85, rationale: 'Financial transaction' },
        actionable: { score: 11, confidence: 80, rationale: 'Requires action' },
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectedLabels).toHaveLength(2);
      expect(result.selectedLabels.map((l) => l.category)).toEqual(['financial', 'actionable']);
    });

    test('should reject non-allowed combinations when strict mode enabled', () => {
      // Override config to be more restrictive
      const restrictiveConfig = {
        ...mockConfig,
        allowedCombinations: ['financial+actionable'], // Only this combination allowed
        strictCombinationMode: true,
      };

      stage = new MultiLabelSelectionStage(restrictiveConfig, mockThresholds);

      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 12, confidence: 85, rationale: 'Financial transaction' },
        personal: { score: 11, confidence: 80, rationale: 'Personal communication' }, // Not allowed with financial
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectedLabels).toHaveLength(1); // Only primary
      expect(result.selectedLabels[0].category).toBe('financial');
    });

    test('should handle bidirectional combination matching', () => {
      const candidateScores: Record<string, CategoryScore> = {
        actionable: { score: 12, confidence: 85, rationale: 'Action required' }, // Primary
        financial: { score: 11, confidence: 80, rationale: 'Financial aspect' }, // Secondary
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectedLabels).toHaveLength(2);
      expect(result.selectedLabels[0].category).toBe('actionable'); // Primary (highest score)
      expect(result.selectedLabels[1].category).toBe('financial'); // Secondary
    });

    test('should allow default combinations when none explicitly configured', () => {
      const permissiveConfig = {
        ...mockConfig,
        allowedCombinations: [], // Empty = allow all
      };

      stage = new MultiLabelSelectionStage(permissiveConfig, mockThresholds);

      const candidateScores: Record<string, CategoryScore> = {
        personal: { score: 12, confidence: 85, rationale: 'Personal communication' },
        marketing: { score: 10, confidence: 75, rationale: 'Marketing content' },
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectedLabels).toHaveLength(2);
    });
  });

  describe('AI Routing Decision Logic', () => {
    test('should not require AI for high-confidence primary label', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 18, confidence: 95, rationale: 'Very strong financial signals' },
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.needsAiClassification).toBe(false);
      expect(result.selectionSummary.needsAi).toBe(false);
    });

    test('should require AI when no labels selected', () => {
      const candidateScores: Record<string, CategoryScore> = {
        marketing: { score: 2, confidence: 25, rationale: 'Very weak signals' },
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.needsAiClassification).toBe(true);
      expect(result.selectionSummary.needsAi).toBe(true);
    });

    test('should require AI for medium confidence labels', () => {
      const candidateScores: Record<string, CategoryScore> = {
        personal: { score: 10, confidence: 65, rationale: 'Moderate personal signals' }, // Medium confidence
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.needsAiClassification).toBe(true);
    });

    test('should require AI when any label below medium confidence', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 12, confidence: 80, rationale: 'Good financial signals' },
        actionable: { score: 6, confidence: 45, rationale: 'Weak action signals' }, // Below medium
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.needsAiClassification).toBe(true);
    });
  });

  describe('Selection Summary Generation', () => {
    test('should generate comprehensive summary for multi-label selection', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 12, confidence: 85, rationale: 'Strong financial' },
        actionable: { score: 10, confidence: 75, rationale: 'Action required' },
        personal: { score: 5, confidence: 45, rationale: 'Some personal signals' },
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectionSummary).toMatchObject({
        totalLabels: 2, // financial + actionable
        primaryCategory: 'financial',
        selectionMethod: 'multi_label',
        confidenceRange: [75, 85],
      });

      expect(result.selectionSummary.topCategories).toHaveLength(3);
      expect(result.selectionSummary.topCategories[0]).toMatchObject({
        category: 'financial',
        score: 12,
      });
    });

    test('should generate summary for single label selection', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 15, confidence: 90, rationale: 'Strong financial only' },
        personal: { score: 4, confidence: 35, rationale: 'Weak personal' }, // Below gap threshold
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectionSummary).toMatchObject({
        totalLabels: 1,
        primaryCategory: 'financial',
        selectionMethod: 'single_label',
        confidenceRange: [90, 90],
      });
    });

    test('should generate summary for no selection', () => {
      const candidateScores: Record<string, CategoryScore> = {
        marketing: { score: 1, confidence: 15, rationale: 'Very weak' },
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectionSummary).toMatchObject({
        totalLabels: 0,
        primaryCategory: null,
        selectionMethod: 'none_selected',
        confidenceRange: [0, 0],
      });
    });
  });

  describe('Category Decision Updates', () => {
    test('should mark selected categories with appropriate decisions', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 18, confidence: 95, rationale: 'High confidence' }, // Should be 'positive'
        actionable: { score: 12, confidence: 70, rationale: 'Medium confidence' }, // Gap of 6, but within range and >= 8 so gets selected; 12 >= 8 but < 15 so should be 'candidate'
        personal: { score: 4, confidence: 35, rationale: 'Low confidence rejected' }, // Should be 'rejected'
      };

      const result = stage.selectLabels(candidateScores);

      // Check that category decisions are properly updated in the input scores
      expect(candidateScores.financial.decision).toBe('positive');
      expect(candidateScores.financial.decisionRationale).toContain('High confidence');

      expect(candidateScores.actionable.decision).toBe('candidate');
      expect(candidateScores.actionable.decisionRationale).toContain('Medium confidence');

      expect(candidateScores.personal.decision).toBe('rejected');
      expect(candidateScores.personal.decisionRationale).toContain('Below minimum threshold');
    });

    test('should mark non-selected but adequate scores as rejected with constraint rationale', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 12, confidence: 80, rationale: 'Primary selection' },
        personal: { score: 8, confidence: 65, rationale: 'Adequate but not selected' }, // Good score but gap too large
      };

      const result = stage.selectLabels(candidateScores);

      expect(candidateScores.personal.decision).toBe('rejected');
      expect(candidateScores.personal.decisionRationale).toContain('multi-label constraints');
    });
  });

  describe('Edge Cases and Error Handling', () => {
    test('should handle missing score data gracefully', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: undefined as any, confidence: 85, rationale: 'Missing score' },
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectedLabels).toHaveLength(0);
    });

    test('should handle missing confidence data gracefully', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 12, confidence: undefined as any, rationale: 'Missing confidence' },
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectedLabels).toHaveLength(1);
      expect(result.selectedLabels[0].confidence).toBe(0); // Default fallback
    });

    test('should handle identical scores with stable ordering', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 10, confidence: 75, rationale: 'Tied score A' },
        actionable: { score: 10, confidence: 75, rationale: 'Tied score B' },
        personal: { score: 10, confidence: 75, rationale: 'Tied score C' },
      };

      const result = stage.selectLabels(candidateScores);

      // Should have stable, deterministic ordering (e.g., alphabetical by category name)
      expect(result.selectedLabels).toHaveLength(3);
      expect(result.selectedLabels[0].isPrimary).toBe(true);
    });

    test('should handle configuration edge cases', () => {
      const edgeCaseConfig = {
        maxLabels: 0, // Invalid
        minSecondaryConfidence: -1, // Invalid
        allowedCombinations: [],
      };

      expect(() => {
        new MultiLabelSelectionStage(edgeCaseConfig, mockThresholds);
      }).toThrow('Invalid configuration');
    });

    test('should validate threshold consistency', () => {
      const invalidThresholds = {
        highConfidence: 5,
        mediumConfidence: 10, // Medium > High - invalid
        lowConfidence: 15, // Low > Medium > High - invalid
        secondaryLabelMinGap: -1, // Negative gap - invalid
      };

      expect(() => {
        new MultiLabelSelectionStage(mockConfig, invalidThresholds);
      }).toThrow('Invalid threshold configuration');
    });
  });

  describe('Subtype Handling', () => {
    test('should preserve subtype information in selected labels', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: {
          score: 12,
          confidence: 85,
          rationale: 'Financial transaction',
          selectedSubtypeId: 'banking_transaction',
        },
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectedLabels[0]).toMatchObject({
        category: 'financial',
        subtype: 'banking_transaction',
      });
    });

    test('should handle missing subtype gracefully', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: {
          score: 12,
          confidence: 85,
          rationale: 'Financial without subtype',
          selectedSubtypeId: null,
        },
      };

      const result = stage.selectLabels(candidateScores);

      expect(result.selectedLabels[0].subtype).toBeNull();
    });
  });

  describe('Performance and Efficiency', () => {
    test('should handle large number of categories efficiently', () => {
      const startTime = Date.now();

      // Generate 100 categories
      const largeCandidateScores: Record<string, CategoryScore> = {};
      for (let i = 0; i < 100; i++) {
        largeCandidateScores[`category_${i}`] = {
          score: Math.random() * 20,
          confidence: Math.random() * 100,
          rationale: `Category ${i} rationale`,
        };
      }

      const result = stage.selectLabels(largeCandidateScores);

      const duration = Date.now() - startTime;

      expect(duration).toBeLessThan(100); // Should complete in <100ms
      expect(result.selectedLabels.length).toBeLessThanOrEqual(3); // Respects max labels
    });

    test('should maintain stable sorting for reproducible results', () => {
      const candidateScores: Record<string, CategoryScore> = {
        financial: { score: 12, confidence: 85, rationale: 'Financial' },
        actionable: { score: 10, confidence: 75, rationale: 'Actionable' },
      };

      const result1 = stage.selectLabels(candidateScores);
      const result2 = stage.selectLabels(candidateScores);

      expect(result1.selectedLabels).toEqual(result2.selectedLabels);
    });
  });
});

